  ('social-worker-moex-06830', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在族群敏感（ethnic-sensitive）的實務工作中，社會工作者對於少數族群使用「雙重」（dual）的觀點， 認為一個壓迫的社會造成少數族群不利的自我概念，應被下列何系統補償？', '["主流（dominant）系統", "維持（sustaining）系統", "充權（empowerment）系統", "滋養（nurturing）系統"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
