  ('social-worker-moex-06839', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在提供案主家庭有關問題解決能力的訓練時，下列敘述何者錯誤？', '["案主與家庭成員應共同參與契約訂定過程，以決定共同目標", "社會工作者不宜積極介入，應允許案主與家庭有消極或非建設性的互動", "思考範圍可儘量擴大，以腦力激盪方式來找出解決方案", "社會工作者往往在會談較後期才能真正教會成員技巧的使用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
